import React from 'react';

function Media() {
  return (
    <div>
      <div className="fb-page" data-href="https://www.facebook.com/jeffberlinracing/" data-tabs="timeline" data-width="500" data-height="" data-small-header="false" data-adapt-container-width="true" data-hide-cover="false" data-show-facepile="true">
        <blockquote cite="https://www.facebook.com/jeffberlinracing/" class="fb-xfbml-parse-ignore">
          <a href="https://www.facebook.com/jeffberlinracing/">Jeff Berlin Racing</a>
        </blockquote>
      </div>
    </div>
  )
}

export default Media;
